#ifdef __cplusplus
extern "C" {
#endif

#include <stdio.h>
#include <stdlib.h>
#include <sys/time.h>
#include <math.h>
#include <cuda_runtime.h>

#define fp double

#define NUMBER_PAR_PER_BOX 100

#ifdef RD_WG_SIZE_0_0
        #define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define NUMBER_THREADS RD_WG_SIZE
#else
        #define NUMBER_THREADS 128
#endif

#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;

	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;

	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

extern int platform_id_inuse;
extern int device_id_inuse;

static void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *res)
{
	res->tv_sec = t1->tv_sec - t0->tv_sec;
	res->tv_usec = t1->tv_usec - t0->tv_usec;
	if (res->tv_usec < 0) {
		--res->tv_sec;
		res->tv_usec += 1000000;
	}
}

static void cuda_check(cudaError_t err, const char *msg)
{
	if (err != cudaSuccess) {
		printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
		fflush(NULL);
		exit(EXIT_FAILURE);
	}
}

static void cuda_check_last(const char *msg)
{
	cudaError_t err = cudaGetLastError();
	if (err != cudaSuccess) {
		printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString(err));
		fflush(NULL);
		exit(EXIT_FAILURE);
	}
}

__global__ void kernel_gpu_cuda(par_str d_par_gpu,
								dim_str d_dim_gpu,
								const box_str *d_box_gpu,
								const FOUR_VECTOR *d_rv_gpu,
								const fp *d_qv_gpu,
								FOUR_VECTOR *d_fv_gpu)
{
	int bx = blockIdx.x;
	int tx = threadIdx.x;
	int wtx = tx;

	__shared__ FOUR_VECTOR rA_shared[NUMBER_PAR_PER_BOX];
	__shared__ FOUR_VECTOR rB_shared[NUMBER_PAR_PER_BOX];
	__shared__ fp qB_shared[NUMBER_PAR_PER_BOX];

	if (bx < d_dim_gpu.number_boxes) {

		fp a2 = 2 * d_par_gpu.alpha * d_par_gpu.alpha;

		int first_i;
		int pointer;
		int k = 0;
		int first_j;
		int j = 0;

		fp r2;
		fp u2;
		fp vij;
		fp fs;
		fp fxij;
		fp fyij;
		fp fzij;
		THREE_VECTOR d;

		first_i = (int)d_box_gpu[bx].offset;

		while (wtx < NUMBER_PAR_PER_BOX) {
			rA_shared[wtx] = d_rv_gpu[first_i + wtx];
			wtx = wtx + NUMBER_THREADS;
		}
		wtx = tx;

		__syncthreads();

		for (k = 0; k < (1 + d_box_gpu[bx].nn); k++) {

			if (k == 0) {
				pointer = bx;
			}
			else {
				pointer = d_box_gpu[bx].nei[k - 1].number;
			}

			first_j = (int)d_box_gpu[pointer].offset;

			while (wtx < NUMBER_PAR_PER_BOX) {
				rB_shared[wtx] = d_rv_gpu[first_j + wtx];
				qB_shared[wtx] = d_qv_gpu[first_j + wtx];
				wtx = wtx + NUMBER_THREADS;
			}
			wtx = tx;

			__syncthreads();

			while (wtx < NUMBER_PAR_PER_BOX) {

				for (j = 0; j < NUMBER_PAR_PER_BOX; j++) {
					r2 = rA_shared[wtx].v + rB_shared[j].v - DOT(rA_shared[wtx], rB_shared[j]);
					u2 = a2 * r2;
					vij = exp(-u2);
					fs = 2 * vij;
					d.x = rA_shared[wtx].x - rB_shared[j].x;
					fxij = fs * d.x;
					d.y = rA_shared[wtx].y - rB_shared[j].y;
					fyij = fs * d.y;
					d.z = rA_shared[wtx].z - rB_shared[j].z;
					fzij = fs * d.z;
					d_fv_gpu[first_i + wtx].v += qB_shared[j] * vij;
					d_fv_gpu[first_i + wtx].x += qB_shared[j] * fxij;
					d_fv_gpu[first_i + wtx].y += qB_shared[j] * fyij;
					d_fv_gpu[first_i + wtx].z += qB_shared[j] * fzij;
				}

				wtx = wtx + NUMBER_THREADS;
			}

			wtx = tx;

			__syncthreads();
		}
	}
}

void
kernel_gpu_cuda_wrapper(	par_str par_cpu,
							dim_str dim_cpu,
							box_str* box_cpu,
							FOUR_VECTOR* rv_cpu,
							fp* qv_cpu,
							FOUR_VECTOR* fv_cpu)
{
#ifdef TIMING
	struct timeval tv;
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_mem_alloc_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
	      d2h_time = 0, close_time = 0, total_time = 0;
	gettimeofday(&tv_total_start, NULL);
#endif

	int num_devices = 0;
	cuda_check(cudaGetDeviceCount(&num_devices), "cudaGetDeviceCount");
	if (num_devices <= 0) {
		printf("Cuda error: no devices available.\n");
		fflush(NULL);
		exit(EXIT_FAILURE);
	}

	printf("Platform: CUDA\n");

	int device = device_id_inuse;
	if (device < 0 || device >= num_devices) {
		device = 0;
	}

	cudaDeviceProp prop;
	cuda_check(cudaGetDeviceProperties(&prop, device), "cudaGetDeviceProperties");
	printf("Device: %s\n", prop.name);
	cuda_check(cudaSetDevice(device), "cudaSetDevice");

#ifdef TIMING
	gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;
#endif

	size_t local_work_size = NUMBER_THREADS;
	size_t global_work_size = (size_t)dim_cpu.number_boxes * local_work_size;

	printf("# of blocks = %lu, # of threads/block = %lu (ensure that device can handle)\n",
	       (unsigned long)(global_work_size / local_work_size),
	       (unsigned long)local_work_size);

	box_str *d_box_gpu = NULL;
	FOUR_VECTOR *d_rv_gpu = NULL;
	fp *d_qv_gpu = NULL;
	FOUR_VECTOR *d_fv_gpu = NULL;

	cuda_check(cudaMalloc((void **)&d_box_gpu, (size_t)dim_cpu.box_mem), "cudaMalloc d_box_gpu");
	cuda_check(cudaMalloc((void **)&d_rv_gpu, (size_t)dim_cpu.space_mem), "cudaMalloc d_rv_gpu");
	cuda_check(cudaMalloc((void **)&d_qv_gpu, (size_t)dim_cpu.space_mem2), "cudaMalloc d_qv_gpu");
	cuda_check(cudaMalloc((void **)&d_fv_gpu, (size_t)dim_cpu.space_mem), "cudaMalloc d_fv_gpu");

#ifdef TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	tvsub(&tv_mem_alloc_end, &tv_init_end, &tv);
	mem_alloc_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;
#endif

#ifdef TIMING
	cudaEvent_t h2d_start, h2d_stop, kernel_start_ev, kernel_stop_ev, d2h_start, d2h_stop;
	cuda_check(cudaEventCreate(&h2d_start), "cudaEventCreate h2d_start");
	cuda_check(cudaEventCreate(&h2d_stop), "cudaEventCreate h2d_stop");
	cuda_check(cudaEventCreate(&kernel_start_ev), "cudaEventCreate kernel_start");
	cuda_check(cudaEventCreate(&kernel_stop_ev), "cudaEventCreate kernel_stop");
	cuda_check(cudaEventCreate(&d2h_start), "cudaEventCreate d2h_start");
	cuda_check(cudaEventCreate(&d2h_stop), "cudaEventCreate d2h_stop");

	cuda_check(cudaEventRecord(h2d_start, 0), "cudaEventRecord h2d_start");
#endif

	cuda_check(cudaMemcpy(d_box_gpu, box_cpu, (size_t)dim_cpu.box_mem, cudaMemcpyHostToDevice), "cudaMemcpy d_box_gpu");
	cuda_check(cudaMemcpy(d_rv_gpu, rv_cpu, (size_t)dim_cpu.space_mem, cudaMemcpyHostToDevice), "cudaMemcpy d_rv_gpu");
	cuda_check(cudaMemcpy(d_qv_gpu, qv_cpu, (size_t)dim_cpu.space_mem2, cudaMemcpyHostToDevice), "cudaMemcpy d_qv_gpu");
	cuda_check(cudaMemcpy(d_fv_gpu, fv_cpu, (size_t)dim_cpu.space_mem, cudaMemcpyHostToDevice), "cudaMemcpy d_fv_gpu");

#ifdef TIMING
	cuda_check(cudaEventRecord(h2d_stop, 0), "cudaEventRecord h2d_stop");
	cuda_check(cudaEventSynchronize(h2d_stop), "cudaEventSynchronize h2d_stop");
	cuda_check(cudaEventElapsedTime(&h2d_time, h2d_start, h2d_stop), "cudaEventElapsedTime h2d");
	cuda_check(cudaEventRecord(kernel_start_ev, 0), "cudaEventRecord kernel_start");
#endif

	kernel_gpu_cuda<<<(unsigned int)dim_cpu.number_boxes, NUMBER_THREADS>>>(
		par_cpu,
		dim_cpu,
		d_box_gpu,
		d_rv_gpu,
		d_qv_gpu,
		d_fv_gpu
	);
	cuda_check_last("kernel_gpu_cuda launch");

#ifdef TIMING
	cuda_check(cudaEventRecord(kernel_stop_ev, 0), "cudaEventRecord kernel_stop");
	cuda_check(cudaEventSynchronize(kernel_stop_ev), "cudaEventSynchronize kernel_stop");
	cuda_check(cudaEventElapsedTime(&kernel_time, kernel_start_ev, kernel_stop_ev), "cudaEventElapsedTime kernel");
#else
	cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize");
#endif

#ifdef TIMING
	cuda_check(cudaEventRecord(d2h_start, 0), "cudaEventRecord d2h_start");
#endif

	cuda_check(cudaMemcpy(fv_cpu, d_fv_gpu, (size_t)dim_cpu.space_mem, cudaMemcpyDeviceToHost), "cudaMemcpy fv_cpu");

#ifdef TIMING
	cuda_check(cudaEventRecord(d2h_stop, 0), "cudaEventRecord d2h_stop");
	cuda_check(cudaEventSynchronize(d2h_stop), "cudaEventSynchronize d2h_stop");
	cuda_check(cudaEventElapsedTime(&d2h_time, d2h_start, d2h_stop), "cudaEventElapsedTime d2h");
#endif

#ifdef TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	cuda_check(cudaFree(d_rv_gpu), "cudaFree d_rv_gpu");
	cuda_check(cudaFree(d_qv_gpu), "cudaFree d_qv_gpu");
	cuda_check(cudaFree(d_fv_gpu), "cudaFree d_fv_gpu");
	cuda_check(cudaFree(d_box_gpu), "cudaFree d_box_gpu");

#ifdef TIMING
	cuda_check(cudaEventDestroy(h2d_start), "cudaEventDestroy h2d_start");
	cuda_check(cudaEventDestroy(h2d_stop), "cudaEventDestroy h2d_stop");
	cuda_check(cudaEventDestroy(kernel_start_ev), "cudaEventDestroy kernel_start");
	cuda_check(cudaEventDestroy(kernel_stop_ev), "cudaEventDestroy kernel_stop");
	cuda_check(cudaEventDestroy(d2h_start), "cudaEventDestroy d2h_start");
	cuda_check(cudaEventDestroy(d2h_stop), "cudaEventDestroy d2h_stop");

	printf("Time spent in different stages of the application:\n");
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0f + (float) tv.tv_usec / 1000.0f;
	tvsub(&tv_close_end, &tv_total_start, &tv_total_end);
	total_time = tv_total_end.tv_sec * 1000.0f + (float) tv_total_end.tv_usec / 1000.0f;

	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}

#ifdef __cplusplus
}
#endif

